<template>
  <div class="order-list-container">
    <!-- 搜索和筛选区域 -->
    <el-card shadow="never" class="filter-card">
      <el-form :inline="true" :model="listQuery" size="small">
        <el-form-item label="订单号">
          <el-input
            v-model="listQuery.orderNumber"
            placeholder="请输入订单号"
            clearable
            style="width: 200px"
            @keyup.enter.native="handleSearch"
          />
        </el-form-item>
        <el-form-item label="订单状态">
          <el-select v-model="listQuery.status" placeholder="全部" clearable style="width: 140px">
            <el-option label="待付款" :value="10" />
            <el-option label="待发货" :value="20" />
            <el-option label="已发货" :value="30" />
            <el-option label="已完成" :value="40" />
            <el-option label="已取消" :value="0" />
          </el-select>
        </el-form-item>
        <el-form-item label="下单时间">
          <el-date-picker
            v-model="dateRange"
            type="daterange"
            range-separator="至"
            start-placeholder="开始日期"
            end-placeholder="结束日期"
            value-format="yyyy-MM-dd"
            style="width: 240px"
          />
        </el-form-item>
        <el-form-item>
          <el-button type="primary" @click="handleSearch">查询</el-button>
          <el-button @click="resetQuery">重置</el-button>
        </el-form-item>
      </el-form>
    </el-card>

    <!-- 数据表格 -->
    <el-card shadow="never" class="table-card">
      <el-table
        v-loading="listLoading"
        :data="list"
        border
        stripe
        highlight-current-row
        style="width: 100%"
      >
        <el-table-column prop="orderNumber" label="订单号" width="180" />
        <el-table-column prop="userName" label="客户名" width="120" />
        <el-table-column label="商品数" width="80" align="center">
          <template slot-scope="scope">
            {{ scope.row.itemCount || (scope.row.items ? scope.row.items.length : 0) }}
          </template>
        </el-table-column>
        <el-table-column label="总金额" width="120" align="right">
          <template slot-scope="scope">
            <span class="amount-text">¥{{ (scope.row.totalAmount || 0).toFixed(2) }}</span>
          </template>
        </el-table-column>
        <el-table-column label="状态" width="100" align="center">
          <template slot-scope="scope">
            <el-tag :type="getStatusTagType(scope.row.status)" size="small" effect="plain">
              {{ getStatusLabel(scope.row.status) }}
            </el-tag>
          </template>
        </el-table-column>
        <el-table-column prop="createTime" label="下单时间" width="170" />
        <el-table-column label="操作" width="180" fixed="right" align="center">
          <template slot-scope="scope">
            <el-button type="text" size="small" @click="handleDetail(scope.row)">详情</el-button>
            <el-button
              v-if="scope.row.status === 20"
              type="text"
              size="small"
              style="color: #9c6e21"
              @click="handleShip(scope.row)"
            >
              发货
            </el-button>
            <el-button
              v-if="scope.row.status === 30"
              type="text"
              size="small"
              style="color: #67c23a"
              @click="handleComplete(scope.row)"
            >
              完成
            </el-button>
          </template>
        </el-table-column>
      </el-table>

      <!-- 空状态 -->
      <el-empty v-if="!listLoading && list.length === 0" description="暂无数据" />

      <!-- 分页 -->
      <div class="pagination-container">
        <el-pagination
          background
          :current-page="listQuery.page"
          :page-sizes="[10, 20, 30, 50]"
          :page-size="listQuery.pageSize"
          :total="total"
          layout="total, sizes, prev, pager, next, jumper"
          @size-change="handleSizeChange"
          @current-change="handleCurrentChange"
        />
      </div>
    </el-card>

    <!-- 发货弹窗 -->
    <el-dialog
      title="订单发货"
      :visible.sync="shipDialogVisible"
      width="480px"
      :close-on-click-modal="false"
    >
      <el-form
        ref="shipForm"
        :model="shipForm"
        :rules="shipRules"
        label-width="90px"
        size="small"
      >
        <el-form-item label="快递公司" prop="shipCompany">
          <el-select v-model="shipForm.shipCompany" placeholder="请选择快递公司" style="width: 100%">
            <el-option label="顺丰速运" value="SF" />
            <el-option label="中通快递" value="ZTO" />
            <el-option label="圆通速递" value="YTO" />
            <el-option label="韵达速递" value="YD" />
            <el-option label="申通快递" value="STO" />
            <el-option label="EMS" value="EMS" />
            <el-option label="极兔速递" value="JITU" />
            <el-option label="其他" value="OTHER" />
          </el-select>
        </el-form-item>
        <el-form-item label="快递单号" prop="shipNo">
          <el-input v-model="shipForm.shipNo" placeholder="请输入快递单号" />
        </el-form-item>
        <el-form-item label="备注">
          <el-input
            v-model="shipForm.remark"
            type="textarea"
            :rows="2"
            placeholder="选填"
          />
        </el-form-item>
      </el-form>
      <span slot="footer" class="dialog-footer">
        <el-button size="small" @click="shipDialogVisible = false">取 消</el-button>
        <el-button
          size="small"
          type="primary"
          :loading="shipSubmitting"
          @click="confirmShip"
        >
          确 认 发 货
        </el-button>
      </span>
    </el-dialog>
  </div>
</template>

<script>
import orderApi from '@/api/order'

/** 订单状态映射 */
const STATUS_MAP = {
  0: '已取消',
  10: '待付款',
  20: '待发货',
  30: '已发货',
  40: '已完成'
}

/** 状态对应的 Element Tag 类型 */
const STATUS_TAG_TYPE = {
  0: 'danger',
  10: 'info',
  20: 'warning',
  30: '',
  40: 'success'
}

export default {
  name: 'OrderList',

  data() {
    return {
      list: [],
      total: 0,
      listLoading: false,
      listQuery: {
        page: 1,
        pageSize: 10,
        orderNumber: '',
        status: '',
        startDate: '',
        endDate: ''
      },
      dateRange: [],

      // 发货弹窗
      shipDialogVisible: false,
      shipForm: {
        orderId: null,
        shipCompany: '',
        shipNo: '',
        remark: ''
      },
      shipRules: {
        shipCompany: [{ required: true, message: '请选择快递公司', trigger: 'change' }],
        shipNo: [
          { required: true, message: '请输入快递单号', trigger: 'blur' },
          { min: 5, max: 50, message: '快递单号长度为 5~50 位', trigger: 'blur' }
        ]
      },
      shipSubmitting: false
    }
  },

  created() {
    this.fetchData()
  },

  methods: {
    /** 获取状态文字 */
    getStatusLabel(status) {
      return STATUS_MAP[status] || '未知'
    },

    /** 获取状态标签类型 */
    getStatusTagType(status) {
      return STATUS_TAG_TYPE[status] || 'info'
    },

    /** 拉取订单列表 */
    async fetchData() {
      this.listLoading = true
      try {
        const params = { ...this.listQuery }
        if (this.dateRange && this.dateRange.length === 2) {
          params.startDate = this.dateRange[0]
          params.endDate = this.dateRange[1]
        } else {
          params.startDate = ''
          params.endDate = ''
        }
        const res = await orderApi.getList(params)
        if (res.code === 0) {
          this.list = res.data.list || res.data.records || []
          this.total = res.data.total || 0
        } else {
          this.$message.error(res.message || '获取订单列表失败')
        }
      } catch (err) {
        console.error('获取订单列表异常:', err)
      } finally {
        this.listLoading = false
      }
    },

    /** 搜索 */
    handleSearch() {
      this.listQuery.page = 1
      this.fetchData()
    },

    /** 重置 */
    resetQuery() {
      this.dateRange = []
      this.listQuery = {
        page: 1,
        pageSize: 10,
        orderNumber: '',
        status: '',
        startDate: '',
        endDate: ''
      }
      this.fetchData()
    },

    /** 每页条数变化 */
    handleSizeChange(val) {
      this.listQuery.pageSize = val
      this.listQuery.page = 1
      this.fetchData()
    },

    /** 页码变化 */
    handleCurrentChange(val) {
      this.listQuery.page = val
      this.fetchData()
    },

    /** 查看详情 */
    handleDetail(row) {
      this.$router.push(`/order/detail/${row.id}`)
    },

    /** 打开发货弹窗 */
    handleShip(row) {
      this.shipForm = {
        orderId: row.id,
        shipCompany: '',
        shipNo: '',
        remark: ''
      }
      this.shipDialogVisible = true
      this.$nextTick(() => {
        this.$refs.shipForm && this.$refs.shipForm.clearValidate()
      })
    },

    /** 确认发货 */
    confirmShip() {
      this.$refs.shipForm.validate(async (valid) => {
        if (!valid) return
        this.shipSubmitting = true
        try {
          const res = await orderApi.ship(this.shipForm.orderId, {
            shipCompany: this.shipForm.shipCompany,
            shipNo: this.shipForm.shipNo,
            remark: this.shipForm.remark
          })
          if (res.code === 0) {
            this.$message.success('发货成功')
            this.shipDialogVisible = false
            // 更新本地行状态
            const row = this.list.find((r) => r.id === this.shipForm.orderId)
            if (row) row.status = 30
          } else {
            this.$message.error(res.message || '发货失败')
          }
        } catch (err) {
          console.error('发货异常:', err)
          this.$message.error('发货请求异常，请重试')
        } finally {
          this.shipSubmitting = false
        }
      })
    },

    /** 完成订单 */
    handleComplete(row) {
      this.$confirm(`确定将订单「${row.orderNumber}」标记为已完成吗？`, '确认完成', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: 'info'
      })
        .then(async () => {
          try {
            const res = await orderApi.updateStatus(row.id, { status: 40 })
            if (res.code === 0) {
              this.$message.success('订单已完成')
              row.status = 40
            } else {
              this.$message.error(res.message || '操作失败')
            }
          } catch (err) {
            console.error('完成订单异常:', err)
            this.$message.error('操作异常，请重试')
          }
        })
        .catch(() => {})
    }
  }
}
</script>

<style lang="scss" scoped>
.order-list-container {
  padding: 20px;
}

.filter-card {
  margin-bottom: 16px;

  ::v-deep .el-card__body {
    padding: 16px 16px 0;
  }
